   488→/// Resolve the default heat (first racing heat) when no target is specified
   489→pub(crate) fn zjjrpd_resolve_default_heat(gallops: &Gallops) -> Result<String, String> {
   490→    for (heat_key, heat) in &gallops.heats {
   491→        if heat.status == HeatStatus::Racing {
   492→            return Ok(heat_key.clone());
   493→        }
   494→    }
   495→    Err("No racing heats found".to_string())
   496→}
