   188→// ============================================================================
   189→// Silks Sequence Parsing and Building
   190→// ============================================================================
   191→
   192→/// Parse silks into (base, sequence_number)
   193→///
   194→/// Silks ending with a 2-digit sequence number are parsed into base and number.
   195→/// Format: "foo-bar" -> ("foo-bar", None)
   196→///         "foo-bar-01" -> ("foo-bar", Some(1))
   197→///         "foo-bar-42" -> ("foo-bar", Some(42))
   198→pub fn jjrq_parse_silks_sequence(silks: &str) -> (String, Option<u32>) {
   199→    // Use regex ^(.+)-(\d{2})$ for suffix detection
   200→    let re = match Regex::new(r"^(.+)-(\d{2})$") {
   201→        Ok(r) => r,
   202→        Err(_) => {
   203→            // Fallback: return full silks as base, no sequence
   204→            return (silks.to_string(), None);
   205→        }
   206→    };
   207→
   208→    if let Some(caps) = re.captures(silks) {
   209→        if let (Some(base_match), Some(num_match)) = (caps.get(1), caps.get(2)) {
   210→            let base = base_match.as_str().to_string();
   211→            if let Ok(num_str) = num_match.as_str().parse::<u32>() {
   212→                return (base, Some(num_str));
   213→            }
   214→        }
   215→    }
   216→
   217→    // No match: return full silks as base, no sequence
   218→    (silks.to_string(), None)
   219→}
   220→
   221→/// Build garlanded silks: "garlanded-{base}-{seq:02}"
   222→pub fn jjrq_build_garlanded_silks(base: &str, seq: u32) -> String {
   223→    format!("garlanded-{}-{:02}", base, seq)
   224→}
   225→
   226→/// Build continuation silks: "{base}-{seq:02}"
   227→pub fn jjrq_build_continuation_silks(base: &str, seq: u32) -> String {
   228→    format!("{}-{:02}", base, seq)
   229→}
